// RUN: %clang_cc1 -verify -fopenmp -fopenmp-version=51 -x c++ -std=c++20 \
// RUN: -triple x86_64-unknown-unknown -emit-llvm %s -o - | FileCheck %s

// expected-no-diagnostics

void use(int);

// Struct binding.
struct Point {
  int x, y;
};
Point make_point() { return {1, 2}; }
void test_struct() {
  auto [m, n] = make_point();
#pragma omp parallel
  {
    use(m + n);
  }
}

// Pair binding.
struct pair {
  int first;
  int second;
};
pair make_pair(int a, int b) {
  return {a, b};
}
void test_pair() {
  auto [a, b] = make_pair(1, 2);
#pragma omp parallel
  {
    use(a);
  }
}

// Array binding.
void test_array() {
  int arr[2] = {1, 2};
  auto [x, y] = arr;
#pragma omp parallel
  {
    use(x + y);
  }
}

// Binding with bitfields.
struct S {
  int x : 4;
  int y : 4;
};
void test_bitfields() {
  S s{1, 2};
  auto [a, b] = s;
#pragma omp parallel
  {
    use(a + b);
  }
}

// Lambda inside OpenMP with captured bindings.
void test_with_lambda() {
  auto [m, n] = make_point();
#pragma omp parallel for collapse(2)
  for (int i = 0; i < 10; i++)
    for (int j = 0; j < 10; j++)
      [m, n](int i, int j) -> void { return; }(i, j);
}

// Only one binding used.
void test_partial_capture() {
  auto [a, b] = make_pair(1, 2);
#pragma omp parallel
  {
    use(a);
  }
}

// Nested parallel regions.
void test_nested() {
  auto [x, y] = make_point();
#pragma omp parallel
  {
    use(x);
#pragma omp parallel
    {
      use(y);
    }
  }
}

// Multiple bindings in same region.
void test_multiple() {
  auto [a, b] = make_point();
  auto [c, d] = make_pair(3, 4);
#pragma omp parallel
  {
    use(a + b + c + d);
  }
}

// Reference structured binding.
void test_reference_binding() {
  Point p = make_point();
  auto& [m, n] = p;
#pragma omp parallel
  { use(m); }
}
